public boolean canConstruct(String s, int k) {
    int[] charCounts = new int[26];

    for (char c : s.toCharArray()) 
        charCounts[c - 'a']++;

    int oddCount = 0;
    for (int count : charCounts) 
        oddCount += count % 2;

    return oddCount <= k && k <= s.length();
}
```


